// wil_details_FeatureReporting_RecordUsageInCache, a3 in [0x140, 0x17F]:
// CAS loop folds value into *(a2+4) and sets a1[+0x10] = already-present flag

// UNPATCHED (0x1C0002567) - unconditional restamp:
    a1[+0x08] = a3;
    a1[+0x04] = 1;
    a1[+0x0C] = a4;

// PATCHED - guarded restamp:
    if (a1[+0x10] == 0) {   // only when value was NOT already cached
        a1[+0x08] = a3;
        a1[+0x04] = 1;
        a1[+0x0C] = a4;
    }
